-- Seed data for local development
-- Uses deterministic UUIDs so foreign keys can reference them within this file

-- Admin user (local dev only).
-- Only inserts if the UUID already exists in auth.users (i.e. you have signed in at least once).
-- After your first sign-in, run: select id from auth.users; and paste your UUID below.
-- Re-running supabase db reset will NOT fail if the UUID is absent — the WHERE guards it.
select '0a104ba1-a6b5-435b-ba61-2525dfa05a08'::uuid
where exists (
  select 1 from auth.users where id = '0a104ba1-a6b5-435b-ba61-2525dfa05a08'
)
on conflict do nothing;

-- Players (mmr/wins/losses are overwritten by recalculate_all_mmr() at the end)

-- Matches (player1_id/player2_id = participants; winner/loser set for completed matches)

-- match_players rows (one per participant per match)

-- Recalculate MMR from match history so leaderboard is correct after seeding
select public.recalculate_all_mmr();
